}

.hamburger {
    display: none;
    flex-direction: column;
    gap: 5px;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0.75rem;
    min-width: 48px;
    min-height: 48px;
    justify-content: center;
    align-items: center;
    border-radius: 0.5rem;
    transition: background 0.2s ease;
}

.hamburger:hover,
.hamburger:focus {
    background: var(--primary-light);
    outline: 2px solid var(--primary-color);
    outline-offset: 2px;
}

.hamburger:focus-visible {
    outline: 3px solid var(--primary-color);
    outline-offset: 2px;
}

.hamburger span {
    width: calc(var(--space-xl) * var(--phi-half));
    /* Phi-based width */
    height: calc(var(--space-xs) * var(--phi-inv));
    /* Phi-based height */
    background: var(--text-primary);
    border-radius: calc(var(--space-xs) * var(--phi-inv));
    /* Phi-based radius */
    transition: var(--transition);
    /* Phi-timed transition */
