}

.hamburger.active span:nth-child(1) {
    transform: rotate(45deg) translate(calc(var(--space-sm) * var(--phi)), calc(var(--space-sm) * var(--phi)));
    /* Phi-based transform */
}

.hamburger.active span:nth-child(2) {
    opacity: 0;
}

.hamburger.active span:nth-child(3) {
    transform: rotate(-45deg) translate(calc(var(--space-sm) * var(--phi-half)), calc(var(--space-sm) * var(--phi-half) * -1));
    /* Phi-based transform */
}

.mobile-menu {
    display: none;
    position: absolute;
    top: 100%;
    left: 0;
