}

.mobile-menu a:hover,
.mobile-menu a.active {
    background: var(--surface);
    color: var(--primary-color);
}

/* ===== HERO SECTION ===== */

.hero {
    padding: var(--space-5xl) var(--space-lg);
    text-align: center;
    background: var(--primary-ultra-light);
    /* Subtle background fill - no gradient, just soft white space filling */
    position: relative;
    overflow: hidden;
    /* Responsive scaling - maintains proportions on zoom */
    min-height: fit-content;
}

/* Zoom support - elements scale proportionally */
@media (min-resolution: 1.5dppx) {
    .hero {
        padding: clamp(var(--space-3xl), var(--space-5xl), var(--space-6xl)) var(--space-lg);
    }
}

/* Golden Ratio Structural Positioning - Creates Symmetry */
.hero::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: var(--phi-ratio);
    /* 61.8% width - golden ratio division creates visual balance */
    height: 100%;
    background: linear-gradient(135deg, 
        rgba(10, 116, 218, 0.008) 0%, 
        transparent var(--phi-ratio)
    );
    pointer-events: none;
    z-index: 0;
}

.hero::after {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: var(--phi-ratio-inv);
    /* 38.2% width - inverse golden ratio */
    height: var(--phi-ratio);
    /* 61.8% height - creates golden rectangle for symmetry */
    background: radial-gradient(circle at var(--phi-ratio-inv) var(--phi-ratio-inv), 
        rgba(10, 116, 218, 0.006) 0%, 
        transparent 70%
    );
    pointer-events: none;
    z-index: 0;
}

.hero .container {
    position: relative;
    z-index: 1;
}

.hero h1 {
    font-size: var(--font-h1);
    /* Uses phi² modular scale */
    font-size: clamp(calc(var(--text-3xl-practical) * var(--size-hero-title)), calc(5vw * var(--size-hero-title)), calc(var(--text-5xl-practical) * var(--size-hero-title)));
    /* Importance-based sizing: critical importance = largest */
    font-weight: var(--font-weight-extrabold);
    margin-bottom: var(--space-lg);
    color: var(--text-primary);
    /* Color intensity: critical = full saturation */
    background: linear-gradient(135deg, var(--text-primary) 0%, var(--primary-dark) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    /* Gradient text for critical importance - additive semantics */
    line-height: calc(1em * var(--phi));
    /* Phi-based line height for proportional harmony */
    letter-spacing: -0.03em;
    width: var(--phi-ratio);
    /* 61.8% width - golden ratio proportion creates symmetry */
    max-width: 46.25rem;
    /* 740px / 16 = 46.25rem - Text width constraint, scales with zoom */
    margin-left: auto;
    margin-right: auto;
    position: relative;
    z-index: 1;
    /* Centered alignment for authority and balance */
    text-align: center;
}

.hero-subtitle {
    font-size: clamp(var(--text-lg-practical), 2vw, var(--text-xl-practical));
    /* Responsive scaling for readability at zoom */
    color: var(--text-secondary);
    margin-bottom: var(--space-2xl);
    margin-left: auto;
    margin-right: auto;
    line-height: 1.7;
    font-weight: var(--font-weight-normal);
    position: relative;
    z-index: 1;
    width: var(--phi-ratio);
    /* 61.8% width - golden ratio symmetry */
    max-width: 46.25rem;
    /* 740px / 16 = 46.25rem - Text width constraint, scales with zoom */
    text-align: center;
    /* Centered for authority and readability */
}

.hero-cta {
    display: flex;
    gap: var(--space-lg);
    justify-content: center;
    flex-wrap: wrap;
    position: relative;
    z-index: 1;
    width: var(--phi-ratio);
    /* 61.8% width - creates symmetry with other hero elements */
    max-width: 37.5rem;
    /* 600px / 16 = 37.5rem - scales with zoom */
    margin-left: auto;
    margin-right: auto;
}

.btn {
    display: inline-flex;
    align-items: center;
    gap: var(--space-sm);
    padding: var(--btn-md);
    border-radius: var(--border-radius);
    text-decoration: none;
    font-weight: var(--font-weight-semibold);
