    font-size: var(--text-base);
}

.btn-primary {
    background: linear-gradient(135deg, 
        var(--primary-color) var(--gradient-stop-2), 
        var(--primary-dark) var(--gradient-stop-3)
    );
    color: white;
    position: relative;
    overflow: hidden;
    box-shadow: var(--shadow-primary);
    font-size: calc(var(--text-base) * var(--size-card-title));
    /* Importance-based sizing: medium importance = moderate size */
    padding: calc(var(--space-md) * var(--size-card-title)) calc(var(--space-xl) * var(--size-card-title));
    /* Importance-based padding - larger buttons for medium importance */
    font-weight: var(--font-weight-semibold);
    /* Slightly bolder for importance */
}

.btn-primary::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
