}

.search-result-industry {
    display: inline-block;
    background: var(--primary-light);
    color: var(--primary-color);
    padding: 0.25rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: var(--font-weight-medium);
    margin-top: 0.25rem;
}

.search-result-item {
    display: block;
    text-decoration: none;
    color: inherit;
}

/* ===== INQUIRY FORM ===== */

.inquiry-section {
    padding: var(--space-4xl) 0;
    background: var(--gradient-primary);
    /* Primary gradient - unified system */
    background-color: var(--primary-light);
    /* Fallback - primary light */
    position: relative;
    /* Add background pattern for dead space reduction */
    background-image: 
        var(--gradient-primary),
        radial-gradient(circle at var(--phi-spiral-2) var(--phi-spiral-3), rgba(10, 116, 218, var(--opacity-subtle)) 0%, transparent 50%);
    background-size: 100% 100%, calc(var(--phi-grid-cell-h) * var(--phi-cubed)) calc(var(--phi-grid-cell-v) * var(--phi-cubed));
}

/* Golden Ratio Positioning for Inquiry Form */
.inquiry-form {
    max-width: 37.5rem;
    /* 600px / 16 = 37.5rem - scales with zoom */
    width: var(--phi-ratio);
    /* 61.8% width - golden ratio proportion */
    margin: 0 auto;
    background: linear-gradient(135deg, 
        var(--surface-elevated) 0%, 
        var(--primary-light) 100%
    );
    /* Primary light gradient - unified system */
    background-color: var(--surface-elevated);
    /* Fallback */
    padding: var(--space-2xl);
    border-radius: var(--border-radius);
    box-shadow: var(--shadow);
    border: 2px solid var(--accent-primary-bg);
    /* Primary border accent - unified system */
    position: relative;
    overflow: hidden;
}

.inquiry-form::before {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: var(--phi-ratio-inv);
    height: 100%;
    background: radial-gradient(circle at 100% 0%, rgba(10, 116, 218, var(--opacity-subtle)) 0%, transparent 70%);
    pointer-events: none;
    z-index: 0;
}

.inquiry-form > * {
    position: relative;
    z-index: 1;
}

.form-group {
    margin-bottom: var(--space-lg);
    position: relative;
    z-index: 1;
}

.form-group label {
    display: block;
    margin-bottom: var(--space-sm);
    font-weight: var(--font-weight-medium);
    color: var(--text-primary);
}

.form-group input,
.form-group textarea,
.form-group select {
    width: 100%;
    padding: clamp(var(--space-sm), 1.5vw, var(--space-md));
    /* Responsive padding scales with zoom */
    border: 2px solid var(--border);
    border-radius: var(--border-radius);
    font-size: clamp(0.875rem, 1.2vw, var(--text-base));
    /* Minimum 14px for readability - important for forms at zoom */
    font-family: inherit;
    transition: var(--transition);
    /* Forms scale entirely for zoom scenarios */
}

.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
    outline: none;
    border-color: var(--primary-color);
    box-shadow: 0 0 0 3px rgba(10, 116, 218, 0.1), var(--shadow-xs);
    background: var(--surface-elevated);
    transition: var(--transition);
}

.form-group textarea {
    min-height: 120px;
    resize: vertical;
}

.form-disclaimer {
    font-size: var(--text-sm);
    color: var(--text-secondary);
    margin-top: var(--space-md);
    font-style: italic;
}

/* ===== FORM INTERACTION STATES ===== */
/* Reassurance through immediate feedback */

.form-group input:valid,
.form-group textarea:valid,
.form-group select:valid {
    border-color: var(--color-success);
}

.form-group input:invalid:not(:placeholder-shown),
.form-group textarea:invalid:not(:placeholder-shown),
.form-group select:invalid:not(:placeholder-shown) {
