.form-group.success input,
.form-group.success textarea,
.form-group.success select {
    border-color: var(--color-success);
    background-color: var(--color-success-light);
}

.form-group.error input,
.form-group.error textarea,
.form-group.error select {
    border-color: var(--color-error);
    background-color: var(--color-error-light);
}

.form-message {
    padding: var(--space-md);
    border-radius: var(--border-radius);
    margin-top: var(--space-lg);
    font-size: var(--text-sm);
    font-weight: var(--font-weight-medium);
}

.form-message-success {
    background-color: var(--color-success-light);
    color: var(--color-success-dark);
    border: 1px solid var(--color-success);
}

.form-message-error {
    background-color: var(--color-error-light);
    color: var(--color-error-dark);
    border: 1px solid var(--color-error);
}

.btn-primary.success {
    background: var(--color-success);
    color: white;
}

.btn-primary.success:hover {
    background: var(--color-success-dark);
}

/* ===== SEARCH LOADING STATE ===== */
.search-input-wrapper.loading::after {
    content: '';
    position: absolute;
    right: var(--space-lg);
    top: 50%;
    transform: translateY(-50%);
    width: var(--space-lg);
    /* Phi-based sizing */
    height: var(--space-lg);
    border: calc(var(--space-xs) * var(--phi-inv)) solid var(--border);
    /* Phi-based border */
    border-top-color: var(--primary-color);
    border-radius: 50%;
    animation: spin 0.618s linear infinite;
    /* Phi-timed animation */
}

@keyframes spin {
    to { transform: translateY(-50%) rotate(360deg); }
}

/* ===== EVIDENCE CITATION SYSTEM ===== */
/* Truth foundation - every claim carries proof */

.evidence-citation {
    display: inline-flex;
    align-items: center;
    gap: var(--space-xs);
    font-size: var(--text-xs);
    color: var(--text-secondary);
    text-decoration: none;
    margin-left: var(--space-xs);
    transition: var(--transition-fast);
}

.evidence-citation::before {
    content: '[';
    color: var(--primary-color);
}

.evidence-citation::after {
    content: ']';
    color: var(--primary-color);
}

.evidence-citation:hover {
    color: var(--primary-color);
}

.evidence-section {
    margin-top: var(--space-2xl);
    padding: clamp(var(--space-xl), 3vw, var(--space-2xl));
    /* Importance-based padding: medium importance = proportional spacing */
    background: linear-gradient(135deg, 
        var(--surface-elevated) 0%, 
        var(--primary-ultra-light) 50%,
        var(--surface-elevated) 100%
    );
    /* Subtle gradient - more color presence than plain surface */
    background-color: var(--surface-elevated);
    /* Fallback */
    border-left: calc(4px * var(--importance-medium)) solid var(--primary-color);
    /* Importance-based border: medium importance = visible accent */
    border-radius: var(--border-radius);
    position: relative;
    box-shadow: var(--shadow-sm);
    /* Subtle elevation for importance */
}

.evidence-section::before {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: var(--phi-ratio-inv);
    /* 38.2% width - golden ratio division */
    height: 100%;
    background: radial-gradient(circle at 100% 0%, 
        var(--accent-primary-bg) 0%, 
        transparent 70%
    );
    /* Phi tangent - curved gradient following golden spiral */
    pointer-events: none;
    z-index: 0;
    opacity: var(--color-intensity-low);
    /* Low opacity for subtlety - additive semantics */
    border-radius: 0 var(--border-radius) var(--border-radius) 0;
}

.evidence-section h3 {
    font-size: clamp(calc(var(--text-lg) * var(--importance-medium)), 2vw, calc(var(--text-xl-practical) * var(--importance-medium)));
    /* Importance-based sizing: medium importance = φ× larger */
    font-weight: var(--font-weight-bold);
    margin-bottom: calc(var(--space-md) * var(--importance-medium));
    /* Importance-based spacing */
    color: var(--text-primary);
