    margin: 0;
}

.evidence-list li {
    margin-bottom: var(--space-md);
    padding-left: var(--space-lg);
    position: relative;
}

.evidence-list li::before {
    content: '→';
    position: absolute;
    left: 0;
    color: var(--primary-color);
}

.evidence-list a {
    color: var(--primary-color);
    text-decoration: none;
}

.evidence-list a:hover {
