}

/* ===== PROGRESSIVE DISCLOSURE ===== */
/* Reduce cognitive load - show depth when needed */

.card-grid.progressive {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: var(--space-xl);
}

.card-grid.progressive .card:nth-child(n+4) {
    display: none;
