}

/* ===== SECTION STYLES ===== */
/* Enhanced spacing using golden ratio for harmonious proportions */

.section {
    padding: clamp(calc(var(--space-2xl) * 0.7), 3vw, calc(var(--space-4xl) * 0.7)) 0;
    /* Reduced responsive padding - 30% reduction for viewport expansion */
    position: relative;
    /* Full section scaling for zoom scenarios */
    min-height: fit-content;
}

/* Section Spacing Variations - PHI Congruence */
.section:nth-child(even) {
