        font-size: clamp(var(--text-xl-practical), 3vw, var(--text-3xl-practical));
    }

    .section-description {
        width: 100%;
        text-align: center;
        font-size: clamp(var(--text-sm), 1.5vw, var(--text-base));
    }

    .hero-cta {
        width: 100%;
        max-width: 100%;
    }

    .search-bar {
        width: 100%;
        margin: var(--space-2xl) auto;
    }

    .industry-filters {
        width: 100%;
    }

    .inquiry-form {
        width: 100%;
        max-width: 100%;
    }
}

/* Mobile and zoom in scenarios */
@media (max-width: 768px) {
    .hero {
        padding: clamp(var(--space-2xl), 5vw, var(--space-3xl)) var(--space-md);
    }

    .hero h1 {
        font-size: clamp(var(--text-xl-practical), 4.5vw, var(--text-3xl-practical));
        line-height: 1.3;
        /* Slightly tighter line-height on mobile */
    }

    .hero-subtitle {
        font-size: clamp(0.875rem, 2vw, var(--text-lg-practical));
    }

    .section {
        padding: clamp(var(--space-xl), 4vw, var(--space-2xl)) 0;
    }

    .card-grid {
        grid-template-columns: 1fr;
        gap: var(--space-lg);
    }

    .card {
        padding: clamp(var(--space-lg), 3vw, var(--space-xl));
    }

    .hero-cta {
        flex-direction: column;
        gap: var(--space-md);
    }

    .container {
        padding: 0 var(--space-md);
    }
}

/* Small mobile and high zoom scenarios */
@media (max-width: 480px) {
    /* Ensure minimum readable sizes at maximum zoom */
    body {
        font-size: clamp(0.875rem, var(--font-base), 1rem);
        /* Minimum readable size with viewport-relative scaling */
    }

    .hero h1 {
        font-size: clamp(1.5rem, 5vw, var(--text-2xl-practical));
        /* Minimum 24px for readability */
    }

    .section-title {
        font-size: clamp(1.25rem, 4vw, var(--text-xl-practical));
        /* Minimum 20px */
    }

    .card-title {
        font-size: clamp(1rem, 3vw, var(--text-lg-practical));
        /* Minimum 16px */
    }

    .btn {
        padding: var(--space-md) var(--space-lg);
        font-size: clamp(0.875rem, 2vw, 1rem);
        /* Minimum 14px button text */
    }
}

/* Zoom support - handles browser zoom 50% to 200% */
@media (min-resolution: 0.75dppx) {
    /* Zoomed out scenarios - maintain proportions */
    .section {
        padding: clamp(var(--space-xl), 3vw, var(--space-4xl)) 0;
    }
}

/* High DPI and zoom in support */
@media (min-resolution: 2dppx) {
    /* Retina displays and zoom in - maintain crisp rendering */
    .hero h1,
    .section-title,
    .card-title {
        -webkit-font-smoothing: antialiased;
        -moz-osx-font-smoothing: grayscale;
    }
}

/* Very small screens - minimum viable layout */
@media (max-width: 320px) {
    .hero {
        padding: var(--space-xl) var(--space-sm);
    }

    .container {
        padding: 0 var(--space-sm);
    }

    .card {
        padding: var(--space-lg);
    }
}

/* Landscape orientation adjustments */
@media (max-height: 500px) and (orientation: landscape) {
    .hero {
        padding: var(--space-2xl) var(--space-lg);
    }

    .section {
        padding: var(--space-xl) 0;
    }
}

/* ===== BREADCRUMBS ===== */
.breadcrumbs {
    padding: var(--space-lg) var(--space-lg);
    background: var(--primary-ultra-light);
    /* Subtle background fill */
    border-bottom: 1px solid var(--border);
    position: relative;
}

/* Golden Ratio Positioning in Breadcrumbs */
.breadcrumbs::before {
    content: '';
    position: absolute;
    left: 0;
    top: 0;
    width: var(--phi-ratio-inv);
    /* 38.2% - creates golden ratio division */
    height: 100%;
    background: linear-gradient(90deg, 
        rgba(10, 116, 218, 0.005) 0%, 
        transparent 100%
    );
    pointer-events: none;
}

.breadcrumbs .container {
    display: flex;
    align-items: center;
    gap: var(--space-sm);
    flex-wrap: wrap;
}

.breadcrumbs a {
    color: var(--primary-color);
    text-decoration: none;
    transition: var(--transition);
}

.breadcrumbs a:hover {
    text-decoration: underline;
}

.breadcrumbs span {
    color: var(--text-secondary);
}

/* ===== TOPIC CARDS ===== */
.topic-cards {
    margin-top: var(--space-lg);
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    gap: var(--space-md);
}

.topic-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: var(--space-xs);
    padding: var(--space-md);
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    text-decoration: none;
    color: var(--text-primary);
    transition: var(--transition);
    text-align: center;
    font-size: 0.875rem;
    font-weight: var(--font-weight-medium);
}

.topic-card i {
    font-size: 1.25rem;
    color: var(--primary-color);
}

.topic-card:hover {
    background: var(--primary-light);
    border-color: var(--primary-color);
    transform: translateY(-2px);
    box-shadow: var(--shadow-sm);
}

.topic-card span {
    display: block;
    margin-top: var(--space-xs);
}

/* ===== FILTERING ===== */
.industry-filters {
    display: flex;
    gap: var(--space-md);
    margin-bottom: var(--space-2xl);
    flex-wrap: wrap;
    width: var(--phi-ratio);
    /* 61.8% width - golden ratio proportion for filter positioning */
    max-width: 100%;
}

.filter-btn {
    padding: clamp(var(--space-xs), 1vw, var(--space-sm)) clamp(var(--space-md), 2vw, var(--space-lg));
    /* Responsive padding scales with zoom */
    border: 1.5px solid var(--border);
    background: var(--surface-elevated);
    border-radius: var(--radius-md);
    cursor: pointer;
    transition: var(--transition);
    font-weight: var(--font-weight-medium);
    font-size: clamp(0.875rem, 1.2vw, var(--text-base));
    /* Minimum 14px for readability at zoom */
    color: var(--text-secondary);
    position: relative;
    overflow: hidden;
    white-space: nowrap;
    /* Prevents text wrapping on zoom */
}

.filter-btn::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: var(--primary-light);
    transform: scaleX(0);
    transform-origin: left;
    transition: transform var(--transition);
    z-index: 0;
}

.filter-btn > * {
    position: relative;
    z-index: 1;
}

.filter-btn:hover {
    border-color: var(--primary-color);
    color: var(--primary-color);
    box-shadow: var(--shadow-xs);
}

.filter-btn:hover::before {
    transform: scaleX(1);
}

.filter-btn.active {
    background: linear-gradient(135deg, 
        var(--primary-color) var(--gradient-stop-2), 
        var(--primary-dark) var(--gradient-stop-3)
    );
    color: white;
    border-color: var(--primary-color);
    box-shadow: var(--shadow-primary);
}

.filter-btn.active::before {
    display: none;
}

.resource-item {
    transition: var(--transition);
    opacity: 1;
}

.resource-item.hidden {
    display: none;
}

/* ===== SEMANTIC PARENT/CHILD SYSTEM ===== */
/* Cascading semantic effects for hierarchical elements */

.semantic-parent {
    position: relative;
    --semantic-phase: 0;
    /* Base phase for parent */
    --semantic-inheritance: 1;
    /* Inheritance multiplier */
}

.semantic-child {
    position: relative;
    --semantic-phase: calc(var(--semantic-phase, 0) + 0.618);
    /* Child phase builds on parent */
    --semantic-inheritance: calc(var(--semantic-inheritance, 1) * var(--phi-inv));
    /* Child inherits reduced intensity */
}

/* Harmonic phase relationships between parent/child */
.semantic-parent .semantic-child {
    --harmonic-offset: calc(var(--semantic-phase) * var(--phi-inv));
    /* Offset based on parent phase */
}

.semantic-parent .semantic-child:nth-child(odd) {
    --harmonic-offset: calc(var(--harmonic-offset, 0) + var(--phi-inv));
}

.semantic-parent .semantic-child:nth-child(even) {
    --harmonic-offset: calc(var(--harmonic-offset, 0) - var(--phi-inv));
}

/* Cascading semantic effects */
.semantic-parent {
    --semantic-color-intensity: var(--color-intensity-high);
}

.semantic-parent .semantic-child {
    --semantic-color-intensity: calc(var(--semantic-color-intensity, 0.618) * var(--phi-inv));
}

/* Semantic inheritance for colors */
.semantic-parent {
    --semantic-primary: var(--primary-color);
    --semantic-wisdom: var(--primary-dark);
    --semantic-calm: var(--primary-color);
}

.semantic-child {
    color: inherit;
    opacity: calc(0.9 + var(--semantic-inheritance, 1) * 0.1);
}

/* ===== BACKGROUND PATTERNS ===== */
/* Subtle phi-based patterns to reduce dead space */

/* Phi-based grid pattern */
.bg-pattern-phi-grid {
    background-image: 
        linear-gradient(var(--phi-azimuth-1), transparent 0%, transparent calc(var(--phi-ratio-inv) * 100% - 1px), rgba(10, 116, 218, var(--opacity-subtle)) calc(var(--phi-ratio-inv) * 100%), transparent calc(var(--phi-ratio-inv) * 100% + 1px)),
        linear-gradient(var(--phi-azimuth-2), transparent 0%, transparent calc(var(--phi-ratio) * 100% - 1px), rgba(107, 70, 193, var(--opacity-subtle)) calc(var(--phi-ratio) * 100%), transparent calc(var(--phi-ratio) * 100% + 1px));
    background-size: 
        calc(var(--phi-grid-cell-h) * var(--phi)) calc(var(--phi-grid-cell-v) * var(--phi)),
        calc(var(--phi-grid-cell-h) * var(--phi)) calc(var(--phi-grid-cell-v) * var(--phi));
    background-position: 0 0, var(--phi-grid-cell-h) var(--phi-grid-cell-v);
}

/* Radial gradients at phi spiral points - Enterprise Refined */
.bg-pattern-phi-radial {
    background-image: 
        radial-gradient(circle at var(--phi-spiral-2) var(--phi-spiral-3), rgba(10, 116, 218, var(--opacity-subtle)) 0%, transparent 50%),
        radial-gradient(circle at var(--phi-spiral-3) var(--phi-spiral-2), rgba(10, 116, 218, calc(var(--opacity-subtle) * 0.7)) 0%, transparent 50%);
    /* Unified color - primary blue only for enterprise consistency */
    background-size: 
        calc(var(--phi-grid-cell-h) * var(--phi-cubed)) calc(var(--phi-grid-cell-v) * var(--phi-cubed)),
        calc(var(--phi-grid-cell-h) * var(--phi-cubed)) calc(var(--phi-grid-cell-v) * var(--phi-cubed));
}

/* Angular gradient overlays (azimuth-based) - Enterprise Refined */
.bg-pattern-angular {
    background-image: 
        linear-gradient(var(--phi-azimuth-1), transparent 0%, rgba(10, 116, 218, var(--opacity-subtle)) var(--phi-ratio-inv), transparent 100%),
        linear-gradient(var(--phi-azimuth-2), transparent 0%, rgba(10, 116, 218, calc(var(--opacity-subtle) * 0.8)) var(--phi-ratio), transparent 100%);
    /* Unified color - primary blue only for enterprise consistency */
    background-size: 100% 100%, 100% 100%;
    background-blend-mode: multiply;
}

/* Pattern opacity using phi-based values (reduced by 30-40%) */
.bg-pattern-subtle {
    opacity: calc(var(--opacity-subtle) * 0.7);
    /* Reduced by 30% for more subtle patterns */
}

.bg-pattern-light {
    opacity: calc(var(--opacity-soft) * 0.6);
    /* Reduced by 40% - unified to opacity-soft */
}

.bg-pattern-soft {
    opacity: calc(var(--opacity-soft) * 0.65);
    /* Reduced by 35% */
}

/* ===== ENHANCED PHI LINES & TANGENTS ===== */
/* Additional structural elements for dead space reduction */

/* Enhanced vertical phi lines */
.phi-line-vertical {
    position: absolute;
    left: var(--phi-ratio);
    top: 0;
    width: var(--phi-line-width);
    height: 100%;
    background: linear-gradient(180deg,
        transparent 0%,
        rgba(10, 116, 218, var(--opacity-subtle)) var(--phi-spiral-2),
        rgba(10, 116, 218, calc(var(--opacity-subtle) * 1.5)) var(--phi-spiral-3),
        rgba(10, 116, 218, var(--opacity-subtle)) var(--phi-spiral-4),
        transparent 100%
    );
    /* Reduced opacity for enterprise refinement */
    opacity: var(--phi-line-opacity);
    pointer-events: none;
    z-index: 0;
}

.phi-line-vertical-inv {
    left: var(--phi-ratio-inv);
}

/* Enhanced horizontal laterals - Enterprise Refined */
.phi-lateral-horizontal {
    position: absolute;
    top: var(--phi-lateral-position-h);
    left: 0;
    right: 0;
    width: 100%;
    height: var(--phi-line-width);
    background: linear-gradient(90deg,
        transparent 0%,
        rgba(10, 116, 218, var(--opacity-subtle)) var(--phi-spiral-2),
        rgba(10, 116, 218, calc(var(--opacity-subtle) * 1.5)) var(--phi-spiral-3),
        rgba(10, 116, 218, var(--opacity-subtle)) var(--phi-spiral-4),
        transparent 100%
    );
    /* Reduced opacity for enterprise refinement */
    opacity: calc(var(--phi-lateral-opacity) * 0.5);
    /* Further reduced for horizontal laterals */
    pointer-events: none;
    z-index: 0;
}

.phi-lateral-horizontal-inv {
    top: var(--phi-ratio);
}

/* Curved tangents following golden spiral - Enterprise Refined */
.phi-tangent {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: radial-gradient(
        ellipse 150% 100% at var(--phi-ratio) 50%,
        transparent 0%,
        rgba(10, 116, 218, var(--opacity-subtle)) var(--phi-spiral-1),
        rgba(10, 116, 218, calc(var(--opacity-subtle) * 1.5)) var(--phi-spiral-2),
        rgba(10, 116, 218, calc(var(--opacity-subtle) * 2)) var(--phi-spiral-3),
        rgba(10, 116, 218, calc(var(--opacity-subtle) * 1.5)) var(--phi-spiral-4),
        transparent 100%
    );
    /* Unified color - primary blue only for enterprise consistency */
    opacity: var(--phi-tangent-opacity);
    pointer-events: none;
    z-index: 0;
}

/* Angular laterals at phi-based angles */
.phi-lateral-angular-1 {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(
        var(--phi-azimuth-1),
        transparent 0%,
        transparent calc(var(--phi-ratio-inv) * 100% - 1px),
        rgba(10, 116, 218, var(--opacity-subtle)) calc(var(--phi-ratio-inv) * 100%),
        rgba(10, 116, 218, calc(var(--opacity-subtle) * 1.5)) calc(var(--phi-ratio-inv) * 100% + 1px),
        transparent calc(var(--phi-ratio-inv) * 100% + 2px)
    );
    /* Unified primary blue for enterprise consistency */
    opacity: var(--phi-azimuth-opacity);
    pointer-events: none;
    z-index: 0;
}

.phi-lateral-angular-2 {
    background: linear-gradient(
        var(--phi-azimuth-2),
        transparent 0%,
        transparent calc(var(--phi-ratio) * 100% - 1px),
        rgba(10, 116, 218, var(--opacity-subtle)) calc(var(--phi-ratio) * 100%),
        rgba(10, 116, 218, calc(var(--opacity-subtle) * 1.5)) calc(var(--phi-ratio) * 100% + 1px),
        transparent calc(var(--phi-ratio) * 100% + 2px)
    );
    /* Unified primary blue for enterprise consistency */
}

.phi-lateral-angular-3 {
    background: linear-gradient(
        var(--phi-azimuth-3),
        transparent 0%,
        transparent calc(var(--phi-ratio-inv) * 100% - 1px),
        rgba(10, 116, 218, var(--opacity-subtle)) calc(var(--phi-ratio-inv) * 100%),
        rgba(10, 116, 218, calc(var(--opacity-subtle) * 1.5)) calc(var(--phi-ratio-inv) * 100% + 1px),
        transparent calc(var(--phi-ratio-inv) * 100% + 2px)
    );
    /* Unified primary blue for enterprise consistency */
}

.phi-lateral-angular-4 {
    background: linear-gradient(
        var(--phi-azimuth-4),
        transparent 0%,
        transparent calc(var(--phi-ratio) * 100% - 1px),
        rgba(10, 116, 218, var(--opacity-subtle)) calc(var(--phi-ratio) * 100%),
        rgba(10, 116, 218, calc(var(--opacity-subtle) * 1.5)) calc(var(--phi-ratio) * 100% + 1px),
        transparent calc(var(--phi-ratio) * 100% + 2px)
    );
    /* Unified primary blue for enterprise consistency */
}

/* ===== ENHANCED NTH-CHILD VARIATIONS ===== */
/* Expanded Fibonacci-based patterns for unique element treatments */

/* Fibonacci sequence positions: 1, 2, 3, 5, 8, 13, 21, 34, 55... */
.card:nth-child(21n) {
    /* 21st Fibonacci number - subtle emphasis */
    transform: translateY(calc(var(--space-xs) * var(--phi-quarter) * -1));
    border-left-width: calc(5px * var(--size-card-title));
}

.card:nth-child(34n) {
    /* 34th Fibonacci number - moderate emphasis */
    transform: translateY(calc(var(--space-xs) * var(--phi-half) * -1));
    border-left-width: calc(6px * var(--size-card-title));
}

.card:nth-child(55n) {
    /* 55th Fibonacci number - strong emphasis */
    transform: translateY(calc(var(--space-xs) * var(--phi) * -1));
    border-left-width: calc(7px * var(--size-card-title));
}

/* Harmonic phase relationships */
.card:nth-child(3n+1) {
    --harmonic-phase: 0;
}

.card:nth-child(3n+2) {
    --harmonic-phase: calc(var(--phi-inv) * 0.5);
}

.card:nth-child(3n+3) {
    --harmonic-phase: var(--phi-inv);
}

/* Angular transforms based on position */
.card:nth-child(5n) {
    transform: rotate(calc(var(--phi-phase, 0) * 0.5deg));
    transform-origin: center;
}

.card:nth-child(8n) {
    transform: rotate(calc(var(--phi-phase, 0) * -0.3deg));
    transform-origin: center;
}

.card:nth-child(13n) {
    transform: rotate(calc(var(--phi-phase, 0) * 0.2deg));
    transform-origin: center;
}

/* Combined angular and vertical transforms */
.card:nth-child(21n):hover {
    transform: translateY(calc(var(--space-md) * var(--phi) * -1)) rotate(calc(var(--phi-phase, 0) * 0.5deg)) scale(1.02);
}

.card:nth-child(34n):hover {
    transform: translateY(calc(var(--space-md) * var(--phi) * -1)) rotate(calc(var(--phi-phase, 0) * -0.3deg)) scale(1.03);
}

/* ===== PAGE-SPECIFIC LAYOUT CLASSES ===== */

