/* ===== COMPREHENSIVE BLOCK COMBINATIONS ===== */
/* All-encompassing web presence using all blocks in permutations */

/* Multiple background pattern combinations */
.section .bg-pattern-phi-grid.bg-pattern-subtle,
.section .bg-pattern-phi-radial.bg-pattern-subtle,
.section .bg-pattern-angular.bg-pattern-light {
