.section .phi-tangent + .phi-lateral-angular-4 {
    z-index: 0;
}

/* Multiple angular laterals - azimuth-based combinations */
.section .phi-lateral-angular-1 + .phi-lateral-angular-2 {
    opacity: calc(var(--phi-azimuth-opacity) * 0.7);
}

.section .phi-lateral-angular-2 + .phi-lateral-angular-3 {
    opacity: calc(var(--phi-azimuth-opacity) * 0.6);
}

.section .phi-lateral-angular-3 + .phi-lateral-angular-4 {
    opacity: calc(var(--phi-azimuth-opacity) * 0.5);
}

/* All four angular laterals combined - full azimuth coverage */
.section .phi-lateral-angular-1 + .phi-lateral-angular-2 + .phi-lateral-angular-3 + .phi-lateral-angular-4 {
    background-blend-mode: multiply;
    opacity: calc(var(--phi-azimuth-opacity) * 0.4);
