/**
 * Symmetry & Harmony Psychology System
 * 
 * Systematic application of Gestalt principles for visual harmony:
 * - Symmetry modes: bilateral, radial, asymmetric balance
 * - Harmony levels: high, medium, low
 * - Psychology integration: cognitive load reduction, visual rhythm, grouping
 */

/* ===== SYMMETRY MODES ===== */

/* Bilateral Symmetry - Mirror elements across vertical/horizontal axes */
[data-symmetry="bilateral"],
.symmetry-bilateral {
    /* Vertical bilateral symmetry */
    --symmetry-axis: vertical;
    --symmetry-mirror-x: 50%;
    --symmetry-mirror-y: 50%;
}

.symmetry-bilateral-vertical {
    /* Elements mirrored across vertical center */
    position: relative;
}

.symmetry-bilateral-vertical > *:nth-child(odd) {
    transform-origin: left center;
}

.symmetry-bilateral-vertical > *:nth-child(even) {
    transform-origin: right center;
    /* Mirror effect through positioning */
}

.symmetry-bilateral-horizontal {
    /* Elements mirrored across horizontal center */
    position: relative;
}

.symmetry-bilateral-horizontal > *:nth-child(odd) {
    transform-origin: center top;
}

.symmetry-bilateral-horizontal > *:nth-child(even) {
    transform-origin: center bottom;
}

/* Radial Symmetry - Rotational symmetry around center points */
[data-symmetry="radial"],
.symmetry-radial {
    --symmetry-center-x: 50%;
    --symmetry-center-y: 50%;
    --symmetry-rotation: 0deg;
    position: relative;
}

.symmetry-radial > * {
    position: absolute;
    transform-origin: var(--symmetry-center-x) var(--symmetry-center-y);
}

/* Radial symmetry with phi-based rotation */
.symmetry-radial-phi > *:nth-child(1) { --symmetry-rotation: 0deg; }
.symmetry-radial-phi > *:nth-child(2) { --symmetry-rotation: 137.5deg; } /* Golden angle */
.symmetry-radial-phi > *:nth-child(3) { --symmetry-rotation: 275deg; }
.symmetry-radial-phi > *:nth-child(4) { --symmetry-rotation: 52.5deg; }
.symmetry-radial-phi > *:nth-child(5) { --symmetry-rotation: 190deg; }

/* Asymmetric Balance - Visual weight distribution (phi-based) */
[data-symmetry="asymmetric"],
.symmetry-asymmetric {
    --asymmetric-weight-left: var(--phi-ratio-inv);
    --asymmetric-weight-right: var(--phi-ratio);
    /* 38.2% / 61.8% weight distribution */
    display: flex;
}

.symmetry-asymmetric > *:first-child {
    flex: var(--asymmetric-weight-left);
}

.symmetry-asymmetric > *:last-child {
    flex: var(--asymmetric-weight-right);
}

/* ===== HARMONY LEVELS ===== */

/* High Harmony - Strong phi relationships, balanced color psychology */
[data-harmony="high"],
.harmony-high {
    --harmony-phi-strength: 1.618;
    --harmony-color-balance: 1;
    --harmony-spacing-ratio: var(--phi);
    --harmony-visual-rhythm: 0.618;
}

.harmony-high * {
    transition-timing-function: cubic-bezier(0.618, 0, 0.382, 1);
    /* Phi-based easing for smooth harmony */
}

/* Medium Harmony - Moderate relationships, subtle variations */
[data-harmony="medium"],
.harmony-medium {
    --harmony-phi-strength: 1.0;
    --harmony-color-balance: 0.75;
    --harmony-spacing-ratio: 1.2;
    --harmony-visual-rhythm: 0.5;
}

.harmony-medium * {
    transition-timing-function: cubic-bezier(0.5, 0, 0.5, 1);
    /* Balanced easing */
}

/* Low Harmony - Dynamic tension, intentional imbalance */
[data-harmony="low"],
.harmony-low {
    --harmony-phi-strength: 0.618;
    --harmony-color-balance: 0.5;
    --harmony-spacing-ratio: 1.5;
    --harmony-visual-rhythm: 0.3;
}

