import BaseLayout from '../layouts/BaseLayout.astro';
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import Hero from '../components/Hero.astro';
import Card from '../components/Card.astro';
import CardGrid from '../components/CardGrid.astro';
import Breadcrumbs from '../components/Breadcrumbs.astro';
import SearchBar from '../components/SearchBar.astro';
import IndustryFilters from '../components/IndustryFilters.astro';
import InquiryForm from '../components/InquiryForm.astro';
import SemanticText from '../components/SemanticText.astro';
import { industries } from '../data/industries';

const currentPath = '/resources';
---

<BaseLayout 
  title="Resources - Brisbane Servers"
  description="Industry-specific knowledge hub with insights on technology applications, grants, automation opportunities, and reality-based guidance for Australian SMEs."
>
  <Header currentPath={currentPath} />

  <main id="main-content" role="main">
    <Breadcrumbs items={[
      { label: 'Home', href: '/' },
      { label: 'Resources' }
    ]} />

    <Hero 
      title="Resources & Insights"
      subtitle="Industry-specific knowledge to help you understand what's possible, what's real, and what actually works for your business. Facts, documented proof, and practical guidance."
    />

    <section class="section" style="padding-top: 0;">
      <div class="container">
        <SearchBar />
      </div>
    </section>

    <!-- Layout A: Masonry-style grid with phi proportions -->
    <!-- Comprehensive block usage: phi-line-vertical, phi-line-vertical-inv, phi-lateral-angular-2, bg-pattern-phi-grid -->
    <section class="section" style="background: var(--surface);">
      <div class="bg-pattern-phi-grid bg-pattern-soft"></div>
      <div class="phi-line-vertical phi-line-vertical-inv"></div>
      <div class="phi-lateral-angular-2"></div>
      <div class="container">
        <h2 class="section-title">
          <SemanticText text="Industry-Specific Resources" semanticLevel="high" isParent={true} />
        </h2>
        <p class="section-description">
          <SemanticText text="Insights tailored to your industry. What works in retail differs from healthcare, and hospitality needs different solutions than professional services. Practical guidance specific to Brisbane and Australian business contexts." semanticLevel="normal" isChild={true} />
        </p>

        <IndustryFilters />

        <CardGrid>
          {industries.map((industry) => (
            <Card
              title={industry.name}
              description={industry.description}
              icon={industry.icon}
              href={`/resources/${industry.slug}`}
              industry={industry.slug}
            >
              <a href={`/resources/${industry.slug}`} class="btn btn-secondary" style="margin-top: var(--space-lg);">
                Explore {industry.name}
              </a>

              {industry.topics.length > 0 && (
                <div class="topic-cards" style="margin-top: var(--space-lg);">
                  {industry.topics.map((topic) => (
                    <a href={`/resources/${industry.slug}/${topic.slug}`} class="topic-card">
                      <i class={topic.icon}></i>
                      <span>{topic.name}</span>
                    </a>
                  ))}
                </div>
              )}
            </Card>
          ))}
        </CardGrid>
      </div>
    </section>

    <InquiryForm 
      title="Questions about your industry? I have an idea..."
      subtitle="Share your thoughts, questions, or half-formed ideas. We're here to provide clarity and explore what's possible. You don't need to be the expert—we are."
      locationField={true}
    />
  </main>

  <Footer />
</BaseLayout>

