  industries.forEach((industry) => {
    industry.topics.forEach((topic) => {
      paths.push({
        params: {
          industry: industry.slug,
          topic: topic.slug
        }
      });
    });
  });

  return paths;
}

const { industry: industrySlug, topic: topicSlug } = Astro.params;
