    font-size: var(--text-2xl);
  }

  /* Layout variations - positions can vary for Gestalt cohesion */
  .card-standard {
    /* Default vertical layout */
  }

  .card-wide {
    grid-column: span 2;
  }

  .card-tall {
    grid-row: span 2;
  }

  .card-asymmetric {
    /* Can be positioned differently in grid */
  }

