 * 
 * Provides graceful fallback UI when content fails to load or is unavailable.
 * Implements Gestalt principles through clear visual hierarchy and information grouping.
 */

interface Props {
  title?: string;
  message?: string;
  actionText?: string;
  actionHref?: string;
