  /* Semantic level typography variants - standardized for site-level Gestalt */
  .semantic-high {
    font-weight: 600;
    font-size: inherit;
    color: var(--text-primary);
  }

  .semantic-medium {
    font-weight: 500;
    font-size: inherit;
    color: var(--text-primary);
  }

  .semantic-normal {
    font-weight: 400;
    font-size: inherit;
    color: var(--text-primary);
  }

  /* Parent/Child relationships for hierarchy */
  .semantic-parent {
    font-weight: 600;
    color: var(--primary-dark);
  }

  .semantic-child {
    font-weight: 400;
    color: var(--text-secondary);
  }
